import axios from 'axios';
import React, { useEffect, useState } from 'react';

export const Rasp = () => {
  const [rasps, setRasps] = useState([]);
  const [filters, setFilters] = useState({
    time: '',
    day: '',
    predmet: '',
    group: '',
    teacher: '',
    kurs: '',
    room: '',
  });
  const [uniqueTimes, setUniqueTimes] = useState([]);
  const [uniqueDays, setUniqueDays] = useState([]);
  // Add similar state variables for other fields

  useEffect(() => {
    const fetchRasps = async () => {
      try {
        const response = await axios.get('http://localhost:5555/rasps');
        setRasps(response.data);

        // Extract unique values for each field
        const times = [...new Set(response.data.map((item) => item.time.time))];
        const days = [...new Set(response.data.map((item) => item.day.day))];
        // Extract unique values for other fields

        setUniqueTimes(times);
        setUniqueDays(days);
        // Set unique values for other fields
      } catch (error) {
        console.error('Error fetching data:', error);
      }
    };

    fetchRasps();
  }, []);

  const handleFilterChange = (field, value) => {
    setFilters((prevFilters) => ({ ...prevFilters, [field]: value }));
  };

  // Apply filters to the data
  const filteredRasps = rasps.filter((item) => {
    return (
      (filters.time === '' || item.time.time === filters.time) &&
      (filters.day === '' || item.day.day === filters.day)
      // Apply similar checks for other fields
    );
  });

  return (
    <div className="bg-white px-4 pt-3 pb-4 rounded-sm border border-gray-200 flex-1">
      <strong className="text-gray-700 font-medium">Расписания</strong>
      <div className="border-x border-gray-200 rounded-sm mt-3">
        {/* Filter dropdowns */}
        <div>
          <label>Время:</label>
          <select
            value={filters.time}
            onChange={(e) => handleFilterChange('time', e.target.value)}
          >
            <option value="">Tümü</option>
            {uniqueTimes.map((time) => (
              <option key={time} value={time}>
                {time}
              </option>
            ))}
          </select>
        </div>
        <div>
          <label>День:</label>
          <select
            value={filters.day}
            onChange={(e) => handleFilterChange('day', e.target.value)}
          >
            <option value="">Tümü</option>
            {uniqueDays.map((day) => (
              <option key={day} value={day}>
                {day}
              </option>
            ))}
          </select>
        </div>
        {/* Add similar dropdowns for other fields */}

        <table className="w-full text-gray-700">
          <thead>
            <tr>
              <th>Время</th>
              <th>День</th>
              <th>Предмет</th>
              <th>Группа</th>
              <th>Преподаватель</th>
              <th>Курс</th>
              <th>Кабинет</th>
            </tr>
          </thead>
          <tbody>
            {filteredRasps.map((item) => (
              <tr key={item._id}>
                <td>{item.time.time}</td>
                <td>{item.day.day}</td>
                <td>{item.predmet.predmet}</td>
                <td>{item.group.group_number}</td>
                <td>{item.teacher.teacher}</td>
                <td>{item.group.kurs}</td>
                <td>{item.room}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};
